# --- Helper functions ---

def aggregate_labels_for_image(image_id: str) -> Optional[dict]:
    """Aggregate labels for a single image using majority voting."""
    if image_id not in annotations_store or not annotations_store[image_id]:
        return None

    labels = [ann["label"] for ann in annotations_store[image_id]]
    vote_counts = Counter(labels)
    total_votes = len(labels)
    majority_label, majority_count = vote_counts.most_common(1)[0]
    confidence = majority_count / total_votes

    result = {
        "label": majority_label,
        "confidence": confidence,
        "vote_counts": dict(vote_counts),
        "total_votes": total_votes,
    }

    aggregated_labels[image_id] = result
    return result


def aggregate_all_labels():
    """Recompute aggregated labels for all images."""
    for image_id in annotations_store:
        aggregate_labels_for_image(image_id)


# --- ML components ---

if HAS_ML:
    class LabeledImageDataset(Dataset):
        """Dataset for labeled images."""

        def __init__(self, image_ids, labels, label_to_idx, image_size=224):
            self.image_ids = image_ids
            self.labels = labels
            self.label_to_idx = label_to_idx
            self.transform = transforms.Compose([
                transforms.Resize((image_size, image_size)),
                transforms.ToTensor(),
                transforms.Normalize(mean=[0.485, 0.456, 0.406],
                                     std=[0.229, 0.224, 0.225]),
            ])

        def __len__(self):
            return len(self.image_ids)

        def __getitem__(self, idx):
            image_id = self.image_ids[idx]
            image_data = images_store[image_id]["data"]
            image = Image.open(BytesIO(image_data)).convert("RGB")
            image = self.transform(image)
            label_idx = self.label_to_idx[self.labels[idx]]
            return image, label_idx

    class ImageClassifier(nn.Module):
        """Simple CNN classifier based on ResNet18."""

        def __init__(self, num_classes):
            super().__init__()
            self.backbone = models.resnet18(weights=None)
            num_features = self.backbone.fc.in_features
            self.backbone.fc = nn.Linear(num_features, num_classes)

        def forward(self, x):
            return self.backbone(x)


