# Annotation Management
@app.post("/annotations", response_model=AnnotationResponse)
async def submit_annotation(data: AnnotationSubmit):
    """Submit a label annotation for an image."""
    if data.image_id not in images_store:
        raise HTTPException(status_code=404, detail="Image not found")
    if data.annotator_id not in annotators_store:
        raise HTTPException(status_code=404, detail="Annotator not found")

    # Check if this annotator already labeled this image
    existing = annotations_store.get(data.image_id, [])
    for ann in existing:
        if ann["annotator_id"] == data.annotator_id:
            raise HTTPException(
                status_code=409,
                detail="Annotator has already labeled this image. Use PUT to update.",
            )

    annotation_id = str(uuid.uuid4())[:8]
    timestamp = datetime.utcnow().isoformat()

    annotation = {
        "annotation_id": annotation_id,
        "annotator_id": data.annotator_id,
        "label": data.label,
        "timestamp": timestamp,
    }

    if data.image_id not in annotations_store:
        annotations_store[data.image_id] = []
    annotations_store[data.image_id].append(annotation)

    # Update annotator stats
    annotators_store[data.annotator_id]["annotation_count"] += 1

    # Track label classes
    label_classes.add(data.label)

    # Re-aggregate labels for this image
    aggregate_labels_for_image(data.image_id)

    return AnnotationResponse(
        annotation_id=annotation_id,
        image_id=data.image_id,
        annotator_id=data.annotator_id,
        label=data.label,
        timestamp=timestamp,
    )


@app.put("/annotations")
async def update_annotation(data: AnnotationSubmit):
    """Update an existing annotation."""
    if data.image_id not in images_store:
        raise HTTPException(status_code=404, detail="Image not found")
    if data.annotator_id not in annotators_store:
        raise HTTPException(status_code=404, detail="Annotator not found")

    existing = annotations_store.get(data.image_id, [])
    found = False
    for ann in existing:
        if ann["annotator_id"] == data.annotator_id:
            old_label = ann["label"]
            ann["label"] = data.label
            ann["timestamp"] = datetime.utcnow().isoformat()
            found = True
            break

    if not found:
        raise HTTPException(status_code=404, detail="No existing annotation found for this annotator on this image")

    label_classes.add(data.label)
    aggregate_labels_for_image(data.image_id)

    return {"message": "Annotation updated", "image_id": data.image_id, "new_label": data.label}


@app.post("/annotations/batch")
async def submit_annotations_batch(annotations: list[AnnotationSubmit]):
    """Submit multiple annotations at once."""
    results = []
    errors = []

    for ann_data in annotations:
        try:
            if ann_data.image_id not in images_store:
                errors.append({"image_id": ann_data.image_id, "error": "Image not found"})
                continue
            if ann_data.annotator_id not in annotators_store:
                errors.append({"annotator_id": ann_data.annotator_id, "error": "Annotator not found"})
                continue

            # Check for duplicate
            existing = annotations_store.get(ann_data.image_id, [])
            duplicate = any(a["annotator_id"] == ann_data.annotator_id for a in existing)
            if duplicate:
                errors.append({
                    "image_id": ann_data.image_id,
                    "annotator_id": ann_data.annotator_id,
                    "error": "Duplicate annotation",
                })
                continue

            annotation_id = str(uuid.uuid4())[:8]
            timestamp = datetime.utcnow().isoformat()

            annotation = {
                "annotation_id": annotation_id,
                "annotator_id": ann_data.annotator_id,
                "label": ann_data.label,
                "timestamp": timestamp,
            }

            if ann_data.image_id not in annotations_store:
                annotations_store[ann_data.image_id] = []
            annotations_store[ann_data.image_id].append(annotation)

            annotators_store[ann_data.annotator_id]["annotation_count"] += 1
            label_classes.add(ann_data.label)
            aggregate_labels_for_image(ann_data.image_id)

            results.append({
                "annotation_id": annotation_id,
                "image_id": ann_data.image_id,
                "label": ann_data.label,
            })
        except Exception as e:
            errors.append({"error": str(e)})

    return {"submitted": len(results), "errors": len(errors), "results": results, "error_details": errors}


