# Inter-annotator agreement
@app.get("/agreement")
async def get_inter_annotator_agreement():
    """Calculate inter-annotator agreement statistics."""
    total_images = 0
    unanimous_count = 0
    total_confidence = 0.0
    label_distribution = Counter()

    for image_id, annotations in annotations_store.items():
        if len(annotations) < 2:
            continue

        total_images += 1
        labels = [ann["label"] for ann in annotations]
        vote_counts = Counter(labels)

        for label, count in vote_counts.items():
            label_distribution[label] += count

        majority_label, majority_count = vote_counts.most_common(1)[0]
        confidence = majority_count / len(labels)
        total_confidence += confidence

        if len(vote_counts) == 1:
            unanimous_count += 1

    avg_confidence = total_confidence / total_images if total_images > 0 else 0
    unanimity_rate = unanimous_count / total_images if total_images > 0 else 0

    # Per-annotator stats
    annotator_stats = {}
    for image_id, annotations in annotations_store.items():
        agg = aggregated_labels.get(image_id)
        if not agg:
            continue
        for ann in annotations:
            aid = ann["annotator_id"]
            if aid not in annotator_stats:
                annotator_stats[aid] = {"total": 0, "agrees_with_majority": 0}
            annotator_stats[aid]["total"] += 1
            if ann["label"] == agg["label"]:
                annotator_stats[aid]["agrees_with_majority"] += 1

    for aid in annotator_stats:
        stats = annotator_stats[aid]
        stats["agreement_rate"] = stats["agrees_with_majority"] / stats["total"] if stats["total"] > 0 else 0
        stats["name"] = annotators_store.get(aid, {}).get("name", "Unknown")

    return {
        "images_with_multiple_annotations": total_images,
        "average_confidence": round(avg_confidence, 4),
        "unanimity_rate": round(unanimity_rate, 4),
        "unanimous_count": unanimous_count,
        "label_distribution": dict(label_distribution),
        "annotator_stats": annotator_stats,
    }


# Training
@app.post("/train")
async def train_model(config: TrainingConfig):
    """Train a model on the aggregated labeled data (no validation split)."""
    global trained_model, training_state

    if not HAS_ML:
        raise HTTPException(status_code=503, detail="ML libraries (torch, torchvision, PIL) not available")

    # Gather training data
    aggregate_all_labels()

    train_image_ids = []
    train_labels = []

    for image_id, agg in aggregated_labels.items():
        if agg["total_votes"] >= config.min_votes and image_id in images_store:
            train_image_ids.append(image_id)
            train_labels.append(agg["label"])

    if len(train_image_ids) == 0:
        raise HTTPException(status_code=400, detail="No labeled images available for training")

    unique_labels = sorted(set(train_labels))
    num_classes = len(unique_labels)

    if num_classes < 2:
        raise HTTPException(status_code=400, detail=f"Need at least 2 classes for training, found {num_classes}")

    label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
    idx_to_label = {idx: label for label, idx in label_to_idx.items()}

    training_state["status"] = "training"
    training_state["label_to_idx"] = label_to_idx
    training_state["idx_to_label"] = idx_to_label
    training_state["num_classes"] = num_classes
    training_state["loss_history"] = []

    try:
        # Create dataset and dataloader (no validation split)
        dataset = LabeledImageDataset(
            train_image_ids, train_labels, label_to_idx, image_size=config.image_size
        )
        dataloader = DataLoader(dataset, batch_size=config.batch_size, shuffle=True)

        # Initialize model
        device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        model = ImageClassifier(num_classes).to(device)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=config.learning_rate)

        # Training loop (no validation)
        model.train()
        for epoch in range(config.epochs):
            epoch_loss = 0.0
            correct = 0
            total = 0

            for batch_images, batch_labels in dataloader:
                batch_images = batch_images.to(device)
                batch_labels = batch_labels.to(device)

                optimizer.zero_grad()
                outputs = model(batch_images)
                loss = criterion(outputs, batch_labels)
                loss.backward()
                optimizer.step()

                epoch_loss += loss.item() * batch_images.size(0)
                _, predicted = torch.max(outputs, 1)
                total += batch_labels.size(0)
                correct += (predicted == batch_labels).sum().item()

            avg_loss = epoch_loss / total
            accuracy = correct / total
            training_state["loss_history"].append({
                "epoch": epoch + 1,
                "loss": round(avg_loss, 6),
                "accuracy": round(accuracy, 4),
            })
            training_state["epochs_completed"] = epoch + 1

        # Store trained model
        trained_model = model
        training_state["status"] = "completed"
        training_state["last_trained"] = datetime.utcnow().isoformat()
        training_state["accuracy"] = round(accuracy, 4)

        return {
            "status": "completed",
            "num_training_images": len(train_image_ids),
            "num_classes": num_classes,
            "classes": unique_labels,
            "epochs": config.epochs,
            "final_loss": round(avg_loss, 6),
            "final_accuracy": round(accuracy, 4),
            "loss_history": training_state["loss_history"],
            "device": str(device),
        }

    except Exception as e:
        training_state["status"] = "failed"
        raise HTTPException(status_code=500, detail=f"Training failed: {str(e)}")


@app.get("/train/status")
async def get_training_status():
    """Get the current training status."""
    return training_state


# Prediction
@app.post("/predict/{image_id}", response_model=PredictionResponse)
async def predict_image(image_id: str):
    """Predict label for an already-uploaded image."""
    global trained_model

    if not HAS_ML:
        raise HTTPException(status_code=503, detail="ML libraries not available")
    if trained_model is None:
        raise HTTPException(status_code=400, detail="No trained model available. Train first.")
    if image_id not in images_store:
        raise HTTPException(status_code=404, detail="Image not found")

    device = next(trained_model.parameters()).device
    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    image_data = images_store[image_id]["data"]
    image = Image.open(BytesIO(image_data)).convert("RGB")
    image_tensor = transform(image).unsqueeze(0).to(device)

    trained_model.eval()
    with torch.no_grad():
        outputs = trained_model(image_tensor)
        probabilities = torch.softmax(outputs, dim=1)[0]
        confidence, predicted_idx = torch.max(probabilities, 0)

    idx_to_label = training_state["idx_to_label"]
    predicted_label = idx_to_label[predicted_idx.item()]
    all_probs = {idx_to_label[i]: round(probabilities[i].item(), 4) for i in range(len(probabilities))}

    return PredictionResponse(
        image_id=image_id,
        predicted_label=predicted_label,
        confidence=round(confidence.item(), 4),
        all_probabilities=all_probs,
    )


