@app.get("/stats")
async def get_system_stats():
    """Get overall system statistics."""
    total_images = len(images_store)
    total_annotators = len(annotators_store)
    total_annotations = sum(len(anns) for anns in annotations_store.values())
    images_with_annotations = sum(1 for anns in annotations_store.values() if len(anns) > 0)
    images_without_annotations = total_images - images_with_annotations

    avg_annotations_per_image = total_annotations / total_images if total_images > 0 else 0

    # Label distribution from aggregated labels
    aggregate_all_labels()
    label_dist = Counter(agg["label"] for agg in aggregated_labels.values())

    return {
        "total_images": total_images,
        "total_annotators": total_annotators,
        "total_annotations": total_annotations,
        "images_with_annotations": images_with_annotations,
        "images_without_annotations": images_without_annotations,
        "average_annotations_per_image": round(avg_annotations_per_image, 2),
        "known_label_classes": sorted(label_classes),
        "aggregated_label_distribution": dict(label_dist),
        "training_status": training_state["status"],
        "last_trained": training_state["last_trained"],
    }


@app.get("/export/labels")
async def export_labels(min_votes: int = 1, format: str = "json"):
    """Export aggregated labels."""
    aggregate_all_labels()

    export_data = []
    for image_id, agg in aggregated_labels.items():
        if agg["total_votes"] >= min_votes:
            export_data.append({
                "image_id": image_id,
                "filename": images_store[image_id]["filename"],
                "label": agg["label"],
                "confidence": agg["confidence"],
                "total_votes": agg["total_votes"],
                "vote_counts": agg["vote_counts"],
            })

    if format == "csv":
        lines = ["image_id,filename,label,confidence,total_votes"]
        for item in export_data:
            lines.append(
                f"{item['image_id']},{item['filename']},{item['label']},"
                f"{item['confidence']},{item['total_votes']}"
            )
        return {"format": "csv", "data": "\n".join(lines)}

    return {"format": "json", "total": len(export_data), "labels": export_data}


# Health check
@app.get("/health")
async def health_check():
    """Health check endpoint."""
    return {
        "status": "healthy",
        "ml_available": HAS_ML,
        "images_loaded": len(images_store),
        "total_annotations": sum(len(anns) for anns in annotations_store.values()),
        "model_trained": trained_model is not None,
    }


@app.delete("/images/{image_id}")
async def delete_image(image_id: str):
    """Delete an image and its annotations."""
    if image_id not in images_store:
        raise HTTPException(status_code=404, detail="Image not found")

    del images_store[image_id]

    if image_id in annotations_store:
        # Update annotator counts
        for ann in annotations_store[image_id]:
            aid = ann["annotator_id"]
            if aid in annotators_store:
                annotators_store[aid]["annotation_count"] = max(
                    0, annotators_store[aid]["annotation_count"] - 1
                )
        del annotations_store[image_id]

    if image_id in aggregated_labels:
        del aggregated_labels[image_id]

    return {"message": f"Image {image_id} and its annotations deleted"}


@app.delete("/reset")
async def reset_system():
    """Reset the entire system (clear all data)."""
    global trained_model, training_state
    images_store.clear()
    annotations_store.clear()
    annotators_store.clear()
    aggregated_labels.clear()
    label_classes.clear()
    trained_model = None
    training_state = {
        "status": "idle",
        "last_trained": None,
        "epochs_completed": 0,
        "loss_history": [],
        "accuracy": None,
        "num_classes": 0,
        "label_to_idx": {},
        "idx_to_label": {},
    }
    return {"message": "System reset complete"}


